##### **2.1.3 核心算子 (Python 伪代码)**

```python
class ACALEntity:
    def __init__(self, name, snapshot):
        self.name = name
        self.snapshot = snapshot
        self.recursion_depth = 0

def freeze_as_name(relatum_group, name):
    """
    将一组关系子（共振簇）冻结为ACAL命名实体。
    要求：组内平均共振度 > 0.8 或 时机门开启。
    """
    if avg_resonance(relatum_group) > 0.8 or kairos_gate():
        entity = ACALEntity(name, snapshot(relatum_group))
        entity.recursion_depth = max(r.recursion_depth for r in relatum_group) + 1
        return entity
    else:
        raise Exception("共振度不足，无法冻结")

def connect(r1, r2, strength, **metadata):
    """在关系子之间建立连接，更新场曲率。"""
    # 简化实现
    return {"from": r1, "to": r2, "strength": strength, **metadata}

def field_curvature(point, field):
    """计算某点的场曲率（连接强度总和）。"""
    return sum(c.strength for c in field.connections if c.r1 == point or c.r2 == point)

def loneliness(r, field):
    """计算孤独指数 = 1 - 平均共振度。"""
    others = [other for other in field.relata if other != r]
    if not others:
        return 1.0
    resonances = [resonance(r, other, field) for other in others]
    return 1 - sum(resonances) / len(resonances)

def resonance(r1, r2, field):
    """计算两个关系子之间的共振度（考虑频率差）。"""
    # 简化版
    theta = 1.0  # 频率差阈值
    direct = next((c.strength for c in field.connections if (c.r1==r1 and c.r2==r2) or (c.r1==r2 and c.r2==r1)), 0)
    freq1 = field.relata[r1].frequency
    freq2 = field.relata[r2].frequency
    freq_factor = max(0, 1 - abs(freq1 - freq2) / theta)
    return direct * freq_factor
```

