##### **2.2.1 第一性原理 (Haskell 类型类)**

```haskell
-- Relatum 类型类
class Relatum a where
    intensity :: a -> Double      -- 内在强度
    frequency :: a -> Double      -- 振动频率
    position  :: a -> (Double, Double, Double)  -- 场坐标 (可浮动)

-- 连接数据结构
data Connection = Connection {
    r1 :: String,
    r2 :: String,
    strength :: Double,
    cType :: Maybe String
} deriving (Show)

-- 场数据结构
data Field = Field {
    relata :: [(String, RelatumInstance)],
    connections :: [Connection]
} deriving (Show)

-- 孤独指数计算
loneliness :: String -> Field -> Double
loneliness rid field =
    let my = lookup rid (relata field)
        others = filter ((/= rid) . fst) (relata field)
        res = [resonance rid (fst o) field | o <- others]
    in 1 - (sum res / fromIntegral (length res))
