##### **2.2.2 场曲率计算 (Go 实现)**

```go
package relatio

type Relatum struct {
    ID        string
    Intensity float64
    Frequency float64
    X, Y, Z   float64
}

type Connection struct {
    R1, R2   string
    Strength float64
}

type Field struct {
    Relata      map[string]Relatum
    Connections []Connection
}

// Curvature 计算某点的场曲率（简化：直接连接的强度之和）
func (f *Field) Curvature(pointID string) float64 {
    sum := 0.0
    for _, conn := range f.Connections {
        if conn.R1 == pointID || conn.R2 == pointID {
            sum += conn.Strength
        }
    }
    return sum
}

// Resonance 计算两点间的共振度
func (f *Field) Resonance(id1, id2 string) float64 {
    r1, ok1 := f.Relata[id1]
    r2, ok2 := f.Relata[id2]
    if !ok1 || !ok2 {
        return 0
    }
    // 找直接连接强度
    var directStrength float64
    for _, conn := range f.Connections {
        if (conn.R1 == id1 && conn.R2 == id2) || (conn.R1 == id2 && conn.R2 == id1) {
            directStrength = conn.Strength
            break
        }
    }
    // 频率差因子
    theta := 1.0 // 阈值
    freqDiff := r1.Frequency - r2.Frequency
    if freqDiff < 0 {
        freqDiff = -freqDiff
    }
    freqFactor := 1.0 - freqDiff/theta
    if freqFactor < 0 {
        freqFactor = 0
    }
    return directStrength * freqFactor
}
